require("fs"),async function(){console.log("Fetching products from Firestore...");try{const e=await fetch("https://firestore.googleapis.com/v1/projects/speed-catalogue/databases/(default)/documents/artifacts/speed-catalogue/public/data/products?pageSize=1000"),t=await e.json();if(!t.documents)return void console.error("No products found");const o=t.documents.map(e=>e.name.split("/").pop()).filter(e=>!["_ad_stats_","--global-stats--","_announcements_","_landing_settings_","_home_settings_","_hero_config_"].includes(e));console.log(`Fetched ${o.length} products to warm up.`);let s=0,a=0;const n=10;for(let e=0;e<o.length;e+=n){const t=o.slice(e,e+n).map(async e=>{const t=`https://speedgifts.net/p/${encodeURIComponent(e)}`;try{(await fetch(t)).ok?s++:a++}catch(e){a++}});await Promise.all(t),await new Promise(e=>setTimeout(e,500)),console.log(`Progress: ${Math.min(e+n,o.length)} / ${o.length}`)}console.log(`Manual Cache warming complete. Success: ${s}, Failed: ${a}`)}catch(e){console.error("Error:",e)}}();